#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b,c; scanf("%d %d %d",&a,&b,&c);
        if(a==b && b==c) printf("Equilateral");
        else if(a==b || b==c || a==c) printf("Isosceles");
        else printf("Scalene");
        if(T) printf("\n");
    }
    return 0;
}

